external_knowledge:
- 'episodic journey' refers to each episode;
- 'beacon of insight' metaphorically denotes the episode's title and description;
- 'whispers of feedback echoing under the stars' alludes to the reviews collected for the featured restaurant;
- 'tale of taste' is a metaphor for individual reviews;
- 'culinary star of the stage' symbolizes the featured restaurant in each episode.

sql:
SELECT episode_status, COUNT(*) AS episode_count
FROM episodes
GROUP BY episode_status;

SELECT engagement_device_type, COUNT(engagement_id) AS total_engagements
FROM user_engagement
GROUP BY engagement_device_type;

SELECT *
FROM episodes
WHERE featured_eat_id NOT IN (
  SELECT restaurant_id
  FROM restaurants
);

SELECT DISTINCT u.user_id, u.user_name
FROM users u
INNER JOIN restaurant_reviews rr ON u.user_id = rr.user_id;

SELECT name, restaurant_average_rating
FROM restaurants
WHERE restaurant_average_rating > 4;

SELECT user_name, user_total_views
FROM users
ORDER BY user_total_views DESC;

external_knowledge:
- 'Culinary adventures' metaphorically refers to the episodes in the database;
- 'Stars under the spotlight' is a metaphor for the featured restaurants in these episodes;
- 'Shimmering average ratings' symbolizes the calculated average ratings given by users to each restaurant.

sql:
SELECT 
  (SELECT SUM(episode_views) FROM episodes) AS total_views,
  (SELECT AVG(restaurant_average_rating) FROM restaurants) AS average_rating;

SELECT restaurant_id, COUNT(review_id) AS total_reviews
FROM restaurant_reviews
GROUP BY restaurant_id;

SELECT user_id, AVG(rating) AS average_rating
FROM episode_ratings
GROUP BY user_id;

